%[text] # 例8.8（超解像）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
isVerbose = false;
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example08_08"; % mfilename

imgname = "msipimg01";
imgfmt = "tiff";
%%
%[text] ## 画像データの読込
imgfile = fullfile(datfolder,imgname);
X = im2double(imresize(rgb2gray(imread(imgfile,imgfmt)),[96 96],'bilinear'));
%%
%[text] ## 幾何処理前の画像表示
figure(1) %[output:64078bdf]
imshow(X)  %[output:64078bdf]
title('原画像')  %[output:64078bdf]
%%
%[text] ## 観測画像
rng(0)
varw = (10/255)^2;

% 測定過程
psf = fspecial('average',2);
measureproc = @(x) downsample2(imfilter(x,psf,'conv','circular'),[2 2]); % H
measureadjp = @(x) imfilter(upsample2(x,[2 2]),psf,'corr','circular'); % H.'
U = measureproc(X);

% 測定過程の整合性チェック
assert(norm(U - imresize(X,0.5,'box'),'fro')<1e-6)

% Simulation of AWGN
V = imnoise(measureproc(X),'gaussian',0,varw);

% 随伴関係 <Sx,v> = <x,S.'v> の確認
W = measureadjp(V);
assert(abs(dot(U(:),V(:))-dot(X(:),W(:)))<1e-6)

figure(2) %[output:6c5032d3]
imshow(V) %[output:6c5032d3]
title('観測画像')  %[output:6c5032d3]
%%
%[text] ### 双三次補間
Ya = imresize(V,2,'bicubic');
figure(3) %[output:11c1d958]
imshow(Ya) %[output:11c1d958]
title("双三次補間 PSNR: "+num2str(psnr(X,Ya))+" dB")  %[output:11c1d958]
%[text] ## 
%%
%[text] ### ラッソ正則化超解像
import msip.udhaarwtdec2
import msip.udhaarwtrec2
nlevels = 5;
[coefs,scales] = udhaarwtdec2(V,nlevels);
R = udhaarwtrec2(coefs,scales);
assert(norm(V-R,"fro")^2/numel(V)<1e-18,'Perfect reconstruction is violated.')
% 合成辞書と転置辞書の定義 (Definition of synthesis dictionary  and its adjoint)
adjdic = @(x) udhaarwtdec2(x,nlevels); % D
syndic = @(x) udhaarwtrec2(x,scales);  % D.'

%%
%[text] ### TV正則化超解像
%%
%[text] ## 結果出力
imwrite(Ya,fullfile(resfolder,"fig08-10a.png"))
%imwrite(U,fullfile(resfolder,"fig01-02b.png"))
%imwrite(Y,fullfile(resfolder,"fig01-02c.png"))
%%
function y = downsample2(x,M)
    z = downsample(x,M(1)).';
    y = downsample(z,M(2)).';
end

function y = upsample2(x,M)
z = upsample(x,M(1),M(1)-1).';
y = upsample(z,M(2),M(2)-1).';
end
